import sys
import unittest

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def parse_linked_list(input_str):
    nodes = input_str.split(' -> ')
    head = None
    for node in nodes:
        if head is None:
            head = ListNode(int(node))
        else:
            last_node = head
            while last_node.next:
                last_node = last_node.next
            last_node.next = ListNode(int(node))
    return head

class Solution:
    def swapNodes(self, head, node1, node2):
        if not head or not head.next:
            return head

        p, q = head, head
n        while q and q.val != node2:
            q = q.next
        if not q:
            return head

        while p and p.next.val != node2:
            p = p.next
        p.next, q.next = q.next, p.next
        return head

def main(sys_stdin):
    input_str = sys_stdin.read().strip()
    tokens = input_str.split(', ')
    head = parse_linked_list(tokens[0])
    node1, node2 = int(tokens[1]), int(tokens[2])

    if not head:
        print('')
    else:
        solution = Solution()
        result = solution.swapNodes(head, node1, node2)

        nodes = []
        while result:
            nodes.append(str(result.val))
            result = result.next

        print(' -> '.join(nodes))
